import java.util.PriorityQueue;

public int minBuildTime(int[] blocks, int split) {
    PriorityQueue<Integer> pq = new PriorityQueue<>();

    for (int block : blocks) {
        pq.add(block);
    }

    while (pq.size() > 1) {
        int a = pq.poll();
        int b = pq.poll();
        pq.add(b + split);
    }

    return pq.poll();
}
```

